using UnityEngine;
public class Script
{
    public static object Main()
    {
        // 用 GM 命令传送到指定坐标（最近动物 NetId=23 位置附近）
        // 动物位置 (-66.57, 59.94, -1882.20)，传送到旁边 1m
        var gmMgr = FL.Gameplay.Manager.GMManager.Instance;
        if (gmMgr == null) return "GMManager null";
        gmMgr.SendGMCommand("/kesam gm tp -65.5 59.94 -1882.2");
        return "Teleported near animal";
    }
}
